# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'tasks', 'rubric_levels', 'case_id', 'holdout', 'slices'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('tasks') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'tasks': True, 'slices': True, 'rubric_levels': True, 'holdout': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'tasks': False, 'slices': False, 'rubric_levels': False, 'holdout': False}
missing = {k: valid[k] for k in valid if k != 'holdout'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

